                        rawSpheres = GenerateColumnLayer(layer, ref rng);
                        break;
                    case CloudArchetype.Platform:
                        rawSpheres = GeneratePlatformLayer(layer, ref rng);
                        break;
                    case CloudArchetype.Tree:
                        rawSpheres = GenerateTreeLayer(layer, ref rng);
                        break;
                    default:
                        rawSpheres = GenerateSphereLayer(layer, ref rng);
                        break;
                }

